const buildContent = (r) => {
  const [name, , prep, cook, servings, difficulty, ingredients, steps, tips, , lore] = r
  const li = arr => arr.map(x => `<li>${x}</li>`).join('')
  const meta = `<p><strong>Hazırlık:</strong> ${prep} • <strong>Pişirme:</strong> ${cook} • <strong>Porsiyon:</strong> ${servings} • <strong>Zorluk:</strong> ${difficulty}</p>`
  return `<p><strong>${name}</strong>, ${lore}</p>
<p>Tandırcı Usta mutfağında bu tarifi geleneksel yöntemleriyle, sabırla ve özenle hazırlıyoruz. Aşağıdaki adımları takip ederek sofranıza aynı yöresel lezzeti taşıyabilirsiniz.</p>
${meta}
<h2>Malzemeler</h2>
<ul>${li(ingredients)}</ul>
<h2>Adım Adım Pişirme</h2>
<ol>${li(steps)}</ol>${tips ? `\n<h2>Püf Noktaları</h2>\n<p>${tips}</p>` : ''}`
}

console.log(`${R.length} tarif hazırlandı, ekleniyor...`)
let added = 0, skipped = 0, failed = 0
for (let i = 0; i < R.length; i++) {
  const r = R[i]
  const [name, tag, prep, cook, servings, difficulty, ingredients, steps, tips, excerpt] = r
  const title = `Ustasından ${name} Tarifi`
  const slug = slugify(title)
  const { data: existing } = await sb.from('blog_posts').select('id').eq('slug', slug).maybeSingle()
  if (existing) { console.log(`-  atlandı: ${slug}`); skipped++; continue }
  const row = {
    title,
    slug,
    excerpt,
    content: buildContent(r),
    cover_image_url: img(i, tag),
    published: false,
    post_type: 'blog',
    recipe_data: { prep_time: prep, cook_time: cook, servings, difficulty, ingredients, steps, tips },
    meta_title: `${title} | Tandırcı Usta`,
    meta_description: excerpt.length > 160 ? excerpt.slice(0, 157) + '...' : excerpt,
  }
  const { error } = await sb.from('blog_posts').insert(row)
  if (error) { console.error(`✗ ${slug}: ${error.message}`); failed++; continue }
  console.log(`✓ ${title}`)
  added++
}

console.log(`\nBitti: ${added} eklendi, ${skipped} atlandı, ${failed} hata.`)
